#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use CGI::Carp qw(fatalsToBrowser);
use File::Basename;
use File::Spec;
use Cwd qw(abs_path);

my $log_dir = "/var/log/myapp";

my $q = CGI->new();

print $q->header('text/html');
print $q->start_html(-title => 'Log File Viewer');
print $q->h1('Log File Viewer');

my $filename = $q->param('logfile');

if (!defined $filename || $filename eq '') {
    print $q->p("No log file specified. Please provide a 'logfile' query parameter.");
    print $q->end_html;
    exit 0;
}

# --- Path Traversal Prevention ---

# Remove null bytes
$filename =~ s/\0//g;

# Strip any directory components - only allow a bare filename
$filename = fileparse($filename);

# Reject filenames containing path traversal sequences or suspicious characters
if ($filename =~ /\.\./ || $filename =~ /[\/\\]/ || $filename =~ /[^a-zA-Z0-9._\-]/) {
    print $q->p({-style => 'color: red;'}, "Error: Invalid log filename. Only alphanumeric characters, dots, hyphens, and underscores are allowed.");
    print $q->end_html;
    exit 0;
}

# Reject empty filename after sanitization
if ($filename eq '' || $filename eq '.' || $filename eq '..') {
    print $q->p({-style => 'color: red;'}, "Error: Invalid log filename.");
    print $q->end_html;
    exit 0;
}

# Build the full path and resolve it
my $full_path = File::Spec->catfile($log_dir, $filename);
my $resolved_path = abs_path($full_path);
my $resolved_log_dir = abs_path($log_dir);

# Verify the resolved path is still within the allowed log directory
if (!defined $resolved_path || !defined $resolved_log_dir || index($resolved_path, $resolved_log_dir . '/') != 0) {
    print $q->p({-style => 'color: red;'}, "Error: Access denied. The requested file is outside the allowed log directory.");
    print $q->end_html;
    exit 0;
}

# Ensure it's a regular file (not a symlink to somewhere else, directory, etc.)
if (! -f $resolved_path) {
    print $q->p({-style => 'color: red;'}, "Error: Log file not found or is not a regular file.");
    print $q->end_html;
    exit 0;
}

# Ensure the file is readable
if (! -r $resolved_path) {
    print $q->p({-style => 'color: red;'}, "Error: Log file is not readable.");
    print $q->end_html;
    exit 0;
}

# --- Open and Display the Log File ---

my $fh;
if (!open($fh, '<', $resolved_path)) {
    print $q->p({-style => 'color: red;'}, "Error: Unable to open log file: " . encode_entities($!));
    print $q->end_html;
    exit 0;
}

print $q->h2("Viewing: " . escapeHTML($filename));
print "<pre style='background-color: #f4f4f4; padding: 15px; border: 1px solid #ccc; overflow: auto; max-height: 600px;'>\n";

my $line_count = 0;
my $max_lines = 10000;

while (my $line = <$fh>) {
    $line_count++;
    if ($line_count > $max_lines) {
        print escapeHTML("[Output truncated after $max_lines lines]\n");
        last;
    }
    print escapeHTML($line);
}

close($fh);

print "</pre>\n";
print $q->p("Total lines displayed: $line_count" . ($line_count > $max_lines ? " (truncated)" : ""));
print $q->end_html;